        else:
            opp_term = -800 if d_opp <= 1 else (300 if d_opp == 2 else 120 * d_opp)

        val = res_term + opp_term
        if val > best_val or (val == best_val and (dx, dy) < best):
            best_val = val
            best = (dx, dy)

    if best is None:
        return [0, 0]
    return [int(best[0]), int(best[1])]
